import datetimefrom libs.database.model import Modelfrom libs.database.types import Date, Number, Char, Date, Varchar2class BlacklistListBlocks(Model):    __tablename__ = 'blacklist_list_blocks'    id = Number(field='id')    date_created = Date(field='date_created', default=datetime.datetime.now())    date_modified = Date(field='date_modified')    user_id = Number(field='user_id')    account_id = Number(field='account_id')    blacklist_id = Number(field='blacklist_id')    customer_id = Number(field='customer_id')    bids = Char(field='bids')    questions = Char(field='questions')    motive_id = Number(field='motive_id')    motive_description = Varchar2(field='motive_description')